style:
.simplified-invoice-container {
  max-width: 800px;
  margin: 0 auto;
  padding: 20px;
}
.simplified-invoice-form {
  background: #fff;
  border-radius: 8px;
  box-shadow: 0 2px 8px rgba(0,0,0,0.1);
  padding: 24px;
}
.form-header {
  margin-bottom: 24px;
  padding-bottom: 16px;
  border-bottom: 2px solid #24963E;
}
.form-header h3 {
  margin: 0 0 8px 0;
  color: #24963E;
}
.form-section {
  margin-bottom: 24px;
}
.section-label {
  font-weight: 600;
  color: #333;
  display: block;
  margin-bottom: 12px;
  padding-bottom: 6px;
  border-bottom: 1px solid #eee;
}
.items-table th {
  background: #f8f9fa;
  font-size: 13px;
}
.totals-display {
  background: #f8f9fa;
  border-radius: 6px;
  padding: 16px;
  display: inline-block;
  min-width: 250px;
}
.total-row {
  display: flex;
  justify-content: space-between;
  padding: 4px 0;
}
.grand-total {
  font-size: 18px;
  font-weight: 700;
  border-top: 2px solid #24963E;
  margin-top: 8px;
  padding-top: 8px;
  color: #24963E;
}
.actions-section {
  padding-top: 16px;
  border-top: 1px solid #eee;
}
.result-section .alert {
  margin-bottom: 0;
}
.add-item-btn {
  margin-top: 8px;
}
.remove-item {
  padding: 2px 6px !important;
}
